    private fun getCipher(): Cipher {
        val keyGenerator = KeyGenerator.getInstance(KeyProperties.KEY_ALGORITHM_AES, keyStoreName)
        val keyGenParameterSpec = KeyGenParameterSpec.Builder(keyAlias,
